(def hydra_encode_errors_error (fn [match_target] ((fn [match_value] (cond (= (first match_target) :checking) ((fn [y] (list :union (->hydra_core_injection "hydra.errors.Error" (->hydra_core_field "checking" (hydra_encode_error_checking_checking_error y))))) match_value) (= (first match_target) :decoding) ((fn [y] (list :union (->hydra_core_injection "hydra.errors.Error" (->hydra_core_field "decoding" (hydra_encode_errors_decoding_error y))))) match_value) (= (first match_target) :duplicate_binding) ((fn [y] (list :union (->hydra_core_injection "hydra.errors.Error" (->hydra_core_field "duplicateBinding" (hydra_encode_error_core_duplicate_binding_error y))))) match_value) (= (first match_target) :duplicate_field) ((fn [y] (list :union (->hydra_core_injection "hydra.errors.Error" (->hydra_core_field "duplicateField" (hydra_encode_error_core_duplicate_field_error y))))) match_value) (= (first match_target) :other) ((fn [y] (list :union (->hydra_core_injection "hydra.errors.Error" (->hydra_core_field "other" (hydra_encode_errors_other_error y))))) match_value) (= (first match_target) :undefined_field) ((fn [y] (list :union (->hydra_core_injection "hydra.errors.Error" (->hydra_core_field "undefinedField" (hydra_encode_error_core_undefined_field_error y))))) match_value) (= (first match_target) :undefined_term_variable) ((fn [y] (list :union (->hydra_core_injection "hydra.errors.Error" (->hydra_core_field "undefinedTermVariable" (hydra_encode_error_core_undefined_term_variable_error y))))) match_value) (= (first match_target) :untyped_term_variable) ((fn [y] (list :union (->hydra_core_injection "hydra.errors.Error" (->hydra_core_field "untypedTermVariable" (hydra_encode_error_core_untyped_term_variable_error y))))) match_value) (= (first match_target) :unexpected_term_variant) ((fn [y] (list :union (->hydra_core_injection "hydra.errors.Error" (->hydra_core_field "unexpectedTermVariant" (hydra_encode_error_core_unexpected_term_variant_error y))))) match_value) (= (first ma